import React, { useState, useEffect } from 'react';
import { format } from 'date-fns';
import { es } from 'date-fns/locale';
import { 
  Search, 
  Filter, 
  Plus, 
  Eye, 
  Edit, 
  Trash2,
  Package,
  FileText,
  Image,
  Download,
  Upload,
  CheckCircle,
  AlertTriangle,
  Clock,
  ChevronRight,
  ArrowRight,
  GitBranch,
  Workflow,
  Layers,
  Settings
} from 'lucide-react';
import productsService from '../../services/productsService';
import inventoryService from '../../services/inventoryService';
import StatusBadge from '../../components/common/StatusBadge';
import Button from '../../components/common/Button';
import Input from '../../components/common/Input';
import Card from '../../components/common/Card';
import Modal from '../../components/common/Modal';

// Simulación de usuario actual
const currentUser = {
  role: 'admin', // Cambiar a otros roles para probar restricciones
  name: 'Administrador'
};

const Products = () => {
  const [products, setProducts] = useState([]);
  const [customers, setCustomers] = useState([]);
  const [qualityTests, setQualityTests] = useState([]);
  const [kpis, setKpis] = useState(null);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [customerFilter, setCustomerFilter] = useState('');
  const [processFilter, setProcessFilter] = useState('');
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [showProductModal, setShowProductModal] = useState(false);
  const [showProductForm, setShowProductForm] = useState(false);
  const [showProductPanel, setShowProductPanel] = useState(false);
  const [selectedProductForPanel, setSelectedProductForPanel] = useState(null);
  const [accessDenied, setAccessDenied] = useState(false);

  // Estados para el formulario extendido de productos
  const [processes, setProcesses] = useState([]);
  const [releaseInstructions, setReleaseInstructions] = useState([]);
  const [productFormData, setProductFormData] = useState({
    part_number: '',
    revision: '',
    description: '',
    notes: '',
    customer_id: '',
    customer_name: '',
    process_id: '',
    process_name: '',
    is_active: true,
    preview_image: '',
    preview_image_name: '',
    drawing_pdf: '',
    drawing_pdf_name: '',
    quality_tests: [],
    release_instructions_id: '',
    release_instructions_name: ''
  });

  // Verificar permisos de acceso
  const hasAccess = () => {
    const allowedRoles = ['admin', 'supervisor', 'operator', 'planning', 'quality'];
    return allowedRoles.includes(currentUser.role);
  };

  const canEdit = () => {
    const allowedRoles = ['admin', 'planning'];
    return allowedRoles.includes(currentUser.role);
  };

  const canDelete = () => {
    const allowedRoles = ['admin', 'planning'];
    return allowedRoles.includes(currentUser.role);
  };

  useEffect(() => {
    if (!hasAccess()) {
      setAccessDenied(true);
      setLoading(false);
      return;
    }

    fetchData();
  }, []);

  useEffect(() => {
    filterProducts();
  }, [products, searchTerm, customerFilter, processFilter]);

  const fetchData = async () => {
    try {
      const [productsData, customersData, qualityTestsData, kpisData] = await Promise.all([
        productsService.getProducts(),
        inventoryService.getCustomers(),
        productsService.getQualityTestTemplates(),
        productsService.getProductsKPIs()
      ]);

      setProducts(productsData);
      setCustomers(customersData);
      setQualityTests(qualityTestsData);
      setKpis(kpisData);

      // Cargar procesos y instrucciones de liberación (datos demo)
      loadProcessesAndInstructions();

      setLoading(false);
    } catch (error) {
      console.error('Error fetching products data:', error);
      setLoading(false);
    }
  };

  const loadProcessesAndInstructions = () => {
    // Procesos de demo
    const demoProcesses = [
      { id: 'proc-1', code: 'PROC-001', name: 'Zinc Plating', subprocesses: [
        { sequence: 1, name: 'Desengrase', release_parameters: [
          { name: 'Temperatura', value: 60, unit: '°C', type: 'exact' },
          { name: 'Tiempo', value: 5, unit: 'min', type: 'exact' }
        ]},
        { sequence: 2, name: 'Decapado', release_parameters: [
          { name: 'Ácido', value: 'HCl', unit: '%', type: 'range', min: 10, max: 15 },
          { name: 'Tiempo', value: 3, unit: 'min', type: 'exact' }
        ]},
        { sequence: 3, name: 'Zinc Plating', release_parameters: [
          { name: 'Corriente', value: 150, unit: 'A/dm²', type: 'exact' },
          { name: 'Temperatura', value: 25, unit: '°C', type: 'range', min: 20, max: 30 }
        ]}
      ]},
      { id: 'proc-2', code: 'PROC-002', name: 'Anodizado', subprocesses: [
        { sequence: 1, name: 'Limpieza', release_parameters: [
          { name: 'Temperatura', value: 50, unit: '°C', type: 'exact' },
          { name: 'Tiempo', value: 10, unit: 'min', type: 'exact' }
        ]},
        { sequence: 2, name: 'Anodizado', release_parameters: [
          { name: 'Voltaje', value: 15, unit: 'V', type: 'exact' },
          { name: 'Tiempo', value: 30, unit: 'min', type: 'exact' }
        ]}
      ]},
      { id: 'proc-3', code: 'PROC-003', name: 'Cromatizado', subprocesses: [
        { sequence: 1, name: 'Preparación', release_parameters: [
          { name: 'pH', value: 7, unit: 'pH', type: 'range', min: 6.5, max: 7.5 }
        ]},
        { sequence: 2, name: 'Cromatizado', release_parameters: [
          { name: 'Concentración', value: 200, unit: 'ppm', type: 'exact' }
        ]}
      ]},
      { id: 'proc-4', code: 'PROC-004', name: 'Pasivado', subprocesses: [
        { sequence: 1, name: 'Activación', release_parameters: [
          { name: 'Temperatura', value: 45, unit: '°C', type: 'exact' }
        ]},
        { sequence: 2, name: 'Pasivado', release_parameters: [
          { name: 'Tiempo', value: 20, unit: 'min', type: 'exact' },
          { name: 'pH', value: 3.5, unit: 'pH', type: 'range', min: 3, max: 4 }
        ]}
      ]}
    ];

    // Instrucciones de liberación de demo
    const demoReleaseInstructions = [
      { id: 'inst-1', name: 'Instrucción Estándar Zinc Plating', description: 'Proceso estándar para liberación de zinc plating', created_at: new Date('2024-01-10') },
      { id: 'inst-2', name: 'Instrucción Anodizado Aeroespacial', description: 'Requisitos especiales para componentes aeroespaciales', created_at: new Date('2024-01-15') },
      { id: 'inst-3', name: 'Instrucción Cromatizado Decorativo', description: 'Especificaciones para acabados decorativos', created_at: new Date('2024-01-20') },
      { id: 'inst-4', name: 'Instrucción Pasivado Naval', description: 'Requisitos para componentes marinos', created_at: new Date('2024-01-25') }
    ];

    setProcesses(demoProcesses);
    setReleaseInstructions(demoReleaseInstructions);
  };

  const filterProducts = () => {
    // La lógica de filtrado se implementaría aquí
    // Por ahora, mostramos todos los datos
  };

  const getProcessIcon = (processType) => {
    switch (processType) {
      case 'zinc_plating':
        return <Package className="w-4 h-4 text-gray-600" />;
      case 'anodizing':
        return <FileText className="w-4 h-4 text-blue-600" />;
      case 'chromating':
        return <AlertTriangle className="w-4 h-4 text-yellow-600" />;
      case 'passivation':
        return <CheckCircle className="w-4 h-4 text-green-600" />;
      default:
        return <Package className="w-4 h-4 text-gray-600" />;
    }
  };

  const getProcessName = (processType) => {
    switch (processType) {
      case 'zinc_plating':
        return 'Zinc Plating';
      case 'anodizing':
        return 'Anodizado';
      case 'chromating':
        return 'Cromatizado';
      case 'passivation':
        return 'Pasivado';
      default:
        return processType;
    }
  };

  const handleViewProduct = (product) => {
    setSelectedProduct(product);
    setShowProductModal(true);
  };

  const handleProductCodeClick = (product) => {
    setSelectedProductForPanel(product);
    setShowProductPanel(true);
  };

  const handleFileClick = (file, fileName) => {
    if (file && fileName) {
      setSelectedFile({
        name: fileName,
        url: file,
        type: fileName.toLowerCase().endsWith('.pdf') ? 'pdf' : 'image'
      });
      setShowFileViewer(true);
    }
  };

  const handleImageUpload = async (file) => {
    try {
      const result = await productsService.uploadProductImage(file);
      setProductFormData(prev => ({
        ...prev,
        preview_image: result.url,
        preview_image_name: file.name
      }));
      return result;
    } catch (error) {
      console.error('Error uploading image:', error);
      throw error;
    }
  };

  const handlePdfUpload = async (file) => {
    try {
      const result = await productsService.uploadDrawingPdf(file);
      setProductFormData(prev => ({
        ...prev,
        drawing_pdf: result.url,
        drawing_pdf_name: file.name
      }));
      return result;
    } catch (error) {
      console.error('Error uploading PDF:', error);
      throw error;
    }
  };

  // Funciones para el formulario extendido
  const handleProductInputChange = (e) => {
    const { name, value, type, checked } = e.target;
    setProductFormData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));
  };

  const handleProcessChange = (processId) => {
    const selectedProcess = processes.find(p => p.id === processId);
    if (selectedProcess) {
      setProductFormData(prev => ({
        ...prev,
        process_id: processId,
        process_name: selectedProcess.name,
        // Aquí se arrastran automáticamente las liberaciones del proceso
        process_release_parameters: selectedProcess.subprocesses.map(sub => ({
          subprocess_name: sub.name,
          sequence: sub.sequence,
          parameters: sub.release_parameters
        }))
      }));
    }
  };

  const handleCustomerChange = (customerId) => {
    const selectedCustomer = customers.find(c => c.id === customerId);
    if (selectedCustomer) {
      setProductFormData(prev => ({
        ...prev,
        customer_id: customerId,
        customer_name: selectedCustomer.name
      }));
    }
  };

  const handleQualityTestChange = (testId, field, value) => {
    setProductFormData(prev => {
      const updatedTests = prev.quality_tests.map(test => {
        if (test.test_id === testId) {
          return { ...test, [field]: value };
        }
        return test;
      });

      // Si no existe el test, agregarlo
      if (!updatedTests.find(test => test.test_id === testId)) {
        const testTemplate = qualityTests.find(qt => qt.id === testId);
        if (testTemplate) {
          updatedTests.push({
            test_id: testTemplate.test_id,
            name: testTemplate.name,
            description: testTemplate.description,
            sampling_type: 'aql', // aql, sample, full
            aql_value: 0.65,
            sample_quantity: 1,
            specifications: '',
            [field]: value
          });
        }
      }

      return { ...prev, quality_tests: updatedTests };
    });
  };

  const handleQualityTestSamplingChange = (testId, samplingType) => {
    setProductFormData(prev => {
      const updatedTests = prev.quality_tests.map(test => {
        if (test.test_id === testId) {
          return { 
            ...test, 
            sampling_type: samplingType,
            // Resetear valores según el tipo de muestreo
            aql_value: samplingType === 'aql' ? 0.65 : null,
            sample_quantity: samplingType === 'sample' ? 1 : null
          };
        }
        return test;
      });

      return { ...prev, quality_tests: updatedTests };
    });
  };

  const handleProductSubmit = async (e) => {
    e.preventDefault();
    try {
      await productsService.createProduct(productFormData);

      // Resetear formulario
      setProductFormData({
        part_number: '',
        revision: '',
        description: '',
        notes: '',
        customer_id: '',
        customer_name: '',
        process_id: '',
        process_name: '',
        is_active: true,
        preview_image: '',
        preview_image_name: '',
        drawing_pdf: '',
        drawing_pdf_name: '',
        quality_tests: [],
        release_instructions_id: '',
        release_instructions_name: ''
      });

      setShowProductForm(false);

      // Recargar productos
      fetchData();
    } catch (error) {
      console.error('Error creating product:', error);
    }
  };

  const renderKPIs = () => {
    if (!kpis) return null;

    return (
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
        <Card className="p-4">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-secondary-600">Total Productos</p>
              <p className="text-2xl font-bold text-primary-600">{kpis.total_products}</p>
            </div>
            <Package className="w-8 h-8 text-primary-500" />
          </div>
        </Card>

        <Card className="p-4">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-secondary-600">Productos Activos</p>
              <p className="text-2xl font-bold text-success-600">{kpis.active_products}</p>
            </div>
            <CheckCircle className="w-8 h-8 text-success-500" />
          </div>
        </Card>

        <Card className="p-4">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-secondary-600">Con Imágenes</p>
              <p className="text-2xl font-bold text-blue-600">{kpis.products_with_images}</p>
            </div>
            <Image className="w-8 h-8 text-blue-500" />
          </div>
        </Card>

        <Card className="p-4">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-secondary-600">Con Dibujos</p>
              <p className="text-2xl font-bold text-purple-600">{kpis.products_with_drawings}</p>
            </div>
            <FileText className="w-8 h-8 text-purple-500" />
          </div>
        </Card>
      </div>
    );
  };

  // Pantalla de acceso denegado
  if (accessDenied) {
    return (
      <div className="flex items-center justify-center h-64">
        <Card className="p-8 text-center max-w-md">
          <Settings className="w-16 h-16 text-red-500 mx-auto mb-4" />
          <h3 className="text-lg font-semibold text-gray-900 mb-2">
            Acceso Restringido
          </h3>
          <p className="text-gray-600 mb-4">
            Esta sección solo está disponible para personal autorizado.
          </p>
          <p className="text-sm text-gray-500">
            Tu rol actual: <span className="font-medium">{currentUser.role}</span>
          </p>
        </Card>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-secondary-900">Productos</h1>
          <p className="text-secondary-600">Gestión de productos y especificaciones técnicas - Acceso: {currentUser.role}</p>
        </div>
        <div className="flex space-x-3">
          {canEdit() && (
            <Button
              onClick={() => setShowProductForm(true)}
              className="btn-primary"
            >
              <Plus className="w-4 h-4 mr-2" />
              Nuevo Producto
            </Button>
          )}
        </div>
      </div>

      {/* KPIs */}
      {renderKPIs()}

      {/* Filters */}
      <Card>
        <div className="p-4">
          <div className="flex flex-col sm:flex-row gap-4">
            <div className="flex-1">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-secondary-400 w-4 h-4" />
                <Input
                  placeholder="Buscar por número de parte o descripción..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-10"
                />
              </div>
            </div>
            <div className="w-full sm:w-48">
              <select
                value={customerFilter}
                onChange={(e) => setCustomerFilter(e.target.value)}
                className="input"
              >
                <option value="">Todos los clientes</option>
                {customers.map((customer) => (
                  <option key={customer.id} value={customer.id}>
                    {customer.name}
                  </option>
                ))}
              </select>
            </div>
          </div>
        </div>
      </Card>

      {/* Products Table */}
      <Card>
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th className="table-header-cell">Número de Parte</th>
                <th className="table-header-cell">Revisión</th>
                <th className="table-header-cell">Descripción</th>
                <th className="table-header-cell">Cliente</th>
                <th className="table-header-cell">Proceso</th>
                <th className="table-header-cell">Pruebas Calidad</th>
                <th className="table-header-cell">Archivos</th>
                <th className="table-header-cell">Acciones</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {products.map((product) => (
                <tr key={product.id} className="table-row">
                  <td className="table-cell font-medium">
                    <button
                      onClick={() => handleProductCodeClick(product)}
                      className="text-blue-600 hover:text-blue-800 hover:underline font-medium"
                      title="Ver información completa del producto"
                    >
                      {product.part_number}
                    </button>
                  </td>
                  <td className="table-cell">
                    <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                      Rev {product.revision}
                    </span>
                  </td>
                  <td className="table-cell">
                    <div className="max-w-xs truncate" title={product.description}>
                      {product.description}
                    </div>
                  </td>
                  <td className="table-cell">{product.customer_name}</td>
                  <td className="table-cell">
                    <div className="flex items-center">
                      {getProcessIcon(product.process_type)}
                      <span className="ml-2">{getProcessName(product.process_type)}</span>
                    </div>
                  </td>
                  <td className="table-cell">
                    <div className="flex flex-wrap gap-1">
                      {product.quality_tests && product.quality_tests.slice(0, 2).map((test, index) => (
                        <span key={index} className="inline-flex items-center px-2 py-1 rounded-full text-xs font-medium bg-gray-100 text-gray-800">
                          {test.test_id}
                        </span>
                      ))}
                      {product.quality_tests && product.quality_tests.length > 2 && (
                        <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-medium bg-gray-100 text-gray-800">
                          +{product.quality_tests.length - 2}
                        </span>
                      )}
                    </div>
                  </td>
                  <td className="table-cell">
                    <div className="flex space-x-2">
                      {product.preview_image && (
                        <button 
                          onClick={() => handleFileClick(product.preview_image, `imagen_${product.part_number}.jpg`)}
                          className="text-blue-600 hover:text-blue-800" 
                          title="Ver imagen"
                        >
                          {product.preview_image_name && product.preview_image_name.toLowerCase().endsWith('.jpg') || product.preview_image_name.toLowerCase().endsWith('.png') ? (
                            <img 
                              src={product.preview_image} 
                              alt="Preview" 
                              className="w-8 h-8 object-cover rounded border border-gray-300"
                            />
                          ) : (
                            <Image className="w-4 h-4" />
                          )}
                        </button>
                      )}
                      {product.drawing_pdf && (
                        <button 
                          onClick={() => handleFileClick(product.drawing_pdf, `dibujo_${product.part_number}.pdf`)}
                          className="text-purple-600 hover:text-purple-800" 
                          title="Ver dibujo"
                        >
                          <FileText className="w-4 h-4" />
                        </button>
                      )}
                    </div>
                  </td>
                  <td className="table-cell">
                    <div className="flex space-x-2">
                      <button
                        onClick={() => handleViewProduct(product)}
                        className="text-primary-600 hover:text-primary-800"
                        title="Ver detalles"
                      >
                        <Eye className="w-4 h-4" />
                      </button>
                      {canEdit() && (
                        <button
                          className="text-secondary-600 hover:text-secondary-800"
                          title="Editar"
                        >
                          <Edit className="w-4 h-4" />
                        </button>
                      )}
                      {canDelete() && (
                        <button
                          className="text-danger-600 hover:text-danger-800"
                          title="Eliminar"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {products.length === 0 && (
            <div className="text-center py-8 text-secondary-500">
              No se encontraron productos
            </div>
          )}
        </div>
      </Card>

      {/* Product Form Modal */}
      <Modal
        isOpen={showProductForm}
        onClose={() => setShowProductForm(false)}
        title="Nuevo Producto"
        size="full"
      >
        <form onSubmit={handleProductSubmit} className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {/* Información Básica */}
            <div className="lg:col-span-3">
              <h3 className="text-lg font-semibold text-gray-900 mb-4 pb-2 border-b">Información Básica</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Número de Parte *
                  </label>
                  <input
                    type="text"
                    name="part_number"
                    value={productFormData.part_number}
                    onChange={handleProductInputChange}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                    placeholder="Ej: ZP-001-001"
                    required
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Revisión *
                  </label>
                  <input
                    type="text"
                    name="revision"
                    value={productFormData.revision}
                    onChange={handleProductInputChange}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                    placeholder="Ej: A"
                    required
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Cliente *
                  </label>
                  <select
                    name="customer_id"
                    value={productFormData.customer_id}
                    onChange={(e) => handleCustomerChange(e.target.value)}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                    required
                  >
                    <option value="">Seleccionar cliente</option>
                    {customers.map((customer) => (
                      <option key={customer.id} value={customer.id}>
                        {customer.name}
                      </option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Proceso Padre *
                  </label>
                  <select
                    name="process_id"
                    value={productFormData.process_id}
                    onChange={(e) => handleProcessChange(e.target.value)}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                    required
                  >
                    <option value="">Seleccionar proceso</option>
                    {processes.map((process) => (
                      <option key={process.id} value={process.id}>
                        {process.code} - {process.name}
                      </option>
                    ))}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Descripción (Nombre del Producto) *
                  </label>
                  <input
                    type="text"
                    name="description"
                    value={productFormData.description}
                    onChange={handleProductInputChange}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                    placeholder="Ej: Housing, Bracket, etc."
                    required
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Notas/Comentarios para Inspección
                  </label>
                  <textarea
                    name="notes"
                    value={productFormData.notes}
                    onChange={handleProductInputChange}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                    rows="3"
                    placeholder="Notas especiales para inspección..."
                  />
                </div>
              </div>
            </div>

            {/* Archivos del Producto */}
            <div className="lg:col-span-3">
              <h3 className="text-lg font-semibold text-gray-900 mb-4 pb-2 border-b">Archivos del Producto</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Imagen Preview
                  </label>
                  <div className="border-2 border-dashed border-gray-300 rounded-lg p-4 text-center">
                    {productFormData.preview_image ? (
                      <div className="space-y-2">
                        <img 
                          src={productFormData.preview_image} 
                          alt="Preview" 
                          className="w-32 h-32 object-cover mx-auto rounded border border-gray-300"
                        />
                        <p className="text-sm text-gray-600">{productFormData.preview_image_name}</p>
                        <button
                          type="button"
                          onClick={() => {
                            const input = document.createElement('input');
                            input.type = 'file';
                            input.accept = 'image/*';
                            input.onchange = (e) => {
                              const file = e.target.files[0];
                              if (file) {
                                handleImageUpload(file);
                              }
                            };
                            input.click();
                          }}
                          className="text-blue-600 hover:text-blue-800 text-sm"
                        >
                          Cambiar imagen
                        </button>
                      </div>
                    ) : (
                      <div className="space-y-2">
                        <Image className="w-12 h-12 text-gray-400 mx-auto" />
                        <p className="text-sm text-gray-600">Arrastra o haz clic para subir imagen</p>
                        <button
                          type="button"
                          onClick={() => {
                            const input = document.createElement('input');
                            input.type = 'file';
                            input.accept = 'image/*';
                            input.onchange = (e) => {
                              const file = e.target.files[0];
                              if (file) {
                                handleImageUpload(file);
                              }
                            };
                            input.click();
                          }}
                          className="bg-blue-500 text-white px-4 py-2 rounded text-sm hover:bg-blue-600"
                        >
                          Seleccionar Imagen
                        </button>
                      </div>
                    )}
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Dibujo Técnico (PDF)
                  </label>
                  <div className="border-2 border-dashed border-gray-300 rounded-lg p-4 text-center">
                    {productFormData.drawing_pdf ? (
                      <div className="space-y-2">
                        <FileText className="w-12 h-12 text-purple-500 mx-auto" />
                        <p className="text-sm text-gray-600">{productFormData.drawing_pdf_name}</p>
                        <button
                          type="button"
                          onClick={() => {
                            const input = document.createElement('input');
                            input.type = 'file';
                            input.accept = '.pdf';
                            input.onchange = (e) => {
                              const file = e.target.files[0];
                              if (file) {
                                handlePdfUpload(file);
                              }
                            };
                            input.click();
                          }}
                          className="text-purple-600 hover:text-purple-800 text-sm"
                        >
                          Cambiar PDF
                        </button>
                      </div>
                    ) : (
                      <div className="space-y-2">
                        <FileText className="w-12 h-12 text-gray-400 mx-auto" />
                        <p className="text-sm text-gray-600">Arrastra o haz clic para subir PDF</p>
                        <button
                          type="button"
                          onClick={() => {
                            const input = document.createElement('input');
                            input.type = 'file';
                            input.accept = '.pdf';
                            input.onchange = (e) => {
                              const file = e.target.files[0];
                              if (file) {
                                handlePdfUpload(file);
                              }
                            };
                            input.click();
                          }}
                          className="bg-purple-500 text-white px-4 py-2 rounded text-sm hover:bg-purple-600"
                        >
                          Seleccionar PDF
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>

            {/* Configuración de Calidad */}
            <div className="lg:col-span-3">
              <h3 className="text-lg font-semibold text-gray-900 mb-4 pb-2 border-b">Configuración de Calidad</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    AQL (Acceptable Quality Level)
                  </label>
                  <input
                    type="number"
                    name="aql"
                    value={productFormData.aql}
                    onChange={handleProductInputChange}
                    step="0.01"
                    min="0"
                    max="1"
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                    placeholder="0.65"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Instrucción de Liberación
                  </label>
                  <select
                    name="release_instructions_id"
                    value={productFormData.release_instructions_id}
                    onChange={(e) => {
                      const instruction = releaseInstructions.find(r => r.id === e.target.value);
                      setProductFormData(prev => ({
                        ...prev,
                        release_instructions_id: e.target.value,
                        release_instructions_name: instruction ? instruction.name : ''
                      }));
                    }}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  >
                    <option value="">Seleccionar instrucción</option>
                    {releaseInstructions.map((instruction) => (
                      <option key={instruction.id} value={instruction.id}>
                        {instruction.name}
                      </option>
                    ))}
                  </select>
                </div>
              </div>
            </div>

            {/* Parámetros de Liberación */}
            {productFormData.process_release_parameters && productFormData.process_release_parameters.length > 0 && (
              <div className="lg:col-span-3">
                <h3 className="text-lg font-semibold text-gray-900 mb-4 pb-2 border-b">Parámetros de Liberación (Arrastrados del Proceso)</h3>
                <div className="space-y-4">
                  {productFormData.process_release_parameters.map((subprocess, index) => (
                    <div key={index} className="border border-gray-200 rounded-lg p-4">
                      <h4 className="font-medium text-gray-900 mb-3">
                        {subprocess.sequence}. {subprocess.subprocess_name}
                      </h4>
                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                        {subprocess.parameters.map((param, paramIndex) => (
                          <div key={paramIndex} className="bg-gray-50 p-3 rounded">
                            <div className="text-sm font-medium text-gray-700">{param.name}</div>
                            <div className="text-sm text-gray-900">
                              {param.type === 'exact' && `${param.value} ${param.unit}`}
                              {param.type === 'range' && `${param.min}-${param.max} ${param.unit}`}
                              {param.type === 'min' && `≥ ${param.value} ${param.unit}`}
                              {param.type === 'max' && `≤ ${param.value} ${param.unit}`}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>

          <div className="flex justify-end space-x-3">
            <Button
              type="button"
              onClick={() => setShowProductForm(false)}
              className="btn-secondary"
            >
              Cancelar
            </Button>
            <Button
              type="submit"
              className="btn-primary"
            >
              Crear Producto
            </Button>
          </div>
        </form>
      </Modal>

      {/* Product Information Panel */}
      <Modal
        isOpen={showProductPanel}
        onClose={() => setShowProductPanel(false)}
        title="Información Completa del Producto"
        size="full"
      >
        {selectedProductForPanel && (
          <div className="space-y-6">
            {/* Header con imagen preview */}
            <div className="flex items-start space-x-6">
              {selectedProductForPanel.preview_image && (
                <div className="flex-shrink-0">
                  <img 
                    src={selectedProductForPanel.preview_image} 
                    alt="Product Preview" 
                    className="w-48 h-48 object-cover rounded-lg border border-gray-300"
                  />
                </div>
              )}
              <div className="flex-1">
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-500">Número de Parte</label>
                    <p className="text-lg font-semibold text-gray-900">{selectedProductForPanel.part_number}</p>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-500">Revisión</label>
                    <p className="text-lg font-semibold text-gray-900">{selectedProductForPanel.revision}</p>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-500">Cliente</label>
                    <p className="text-lg font-semibold text-gray-900">{selectedProductForPanel.customer_name}</p>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-500">Proceso</label>
                    <p className="text-lg font-semibold text-gray-900">{selectedProductForPanel.process_name}</p>
                  </div>
                </div>
              </div>
            </div>

            {/* Información detallada */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              <div>
                <h3 className="text-lg font-semibold text-gray-900 mb-3">Información del Producto</h3>
                <div className="space-y-3">
                  <div>
                    <label className="block text-sm font-medium text-gray-500">Descripción</label>
                    <p className="text-gray-900">{selectedProductForPanel.description}</p>
                  </div>
                  {selectedProductForPanel.notes && (
                    <div>
                      <label className="block text-sm font-medium text-gray-500">Notas/Comentarios</label>
                      <p className="text-gray-900 bg-yellow-50 p-3 rounded border border-yellow-200">
                        {selectedProductForPanel.notes}
                      </p>
                    </div>
                  )}
                </div>
              </div>

              <div>
                <h3 className="text-lg font-semibold text-gray-900 mb-3">Archivos</h3>
                <div className="space-y-3">
                  {selectedProductForPanel.preview_image && (
                    <div className="flex items-center space-x-3 p-3 border border-gray-200 rounded-lg">
                      <Image className="w-8 h-8 text-blue-500" />
                      <div className="flex-1">
                        <p className="font-medium text-gray-900">Imagen Preview</p>
                        <p className="text-sm text-gray-500">{selectedProductForPanel.preview_image_name}</p>
                      </div>
                      <button
                        onClick={() => handleFileClick(selectedProductForPanel.preview_image, selectedProductForPanel.preview_image_name)}
                        className="text-blue-600 hover:text-blue-800"
                      >
                        Ver
                      </button>
                    </div>
                  )}
                  {selectedProductForPanel.drawing_pdf && (
                    <div className="flex items-center space-x-3 p-3 border border-gray-200 rounded-lg">
                      <FileText className="w-8 h-8 text-purple-500" />
                      <div className="flex-1">
                        <p className="font-medium text-gray-900">Dibujo Técnico</p>
                        <p className="text-sm text-gray-500">{selectedProductForPanel.drawing_pdf_name}</p>
                      </div>
                      <button
                        onClick={() => handleFileClick(selectedProductForPanel.drawing_pdf, selectedProductForPanel.drawing_pdf_name)}
                        className="text-purple-600 hover:text-purple-800"
                      >
                        Ver
                      </button>
                    </div>
                  )}
                </div>
              </div>
            </div>

            {/* Pruebas de Calidad */}
            {selectedProductForPanel.quality_tests && selectedProductForPanel.quality_tests.length > 0 && (
              <div>
                <h3 className="text-lg font-semibold text-gray-900 mb-3">Pruebas de Calidad Configuradas</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                  {selectedProductForPanel.quality_tests.map((test, index) => (
                    <div key={index} className="border border-gray-200 rounded-lg p-4">
                      <h4 className="font-medium text-gray-900 mb-2">{test.name}</h4>
                      <div className="space-y-1 text-sm">
                        <div className="flex justify-between">
                          <span className="text-gray-500">Muestreo:</span>
                          <span className="font-medium">
                            {test.sampling_type === 'aql' && `AQL ${test.aql_value}`}
                            {test.sampling_type === 'sample' && `${test.sample_quantity} muestras`}
                            {test.sampling_type === 'full' && '100%'}
                          </span>
                        </div>
                        {test.specifications && (
                          <div className="flex justify-between">
                            <span className="text-gray-500">Especificaciones:</span>
                            <span className="font-medium">{test.specifications}</span>
                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Parámetros de Liberación */}
            {selectedProductForPanel.process_release_parameters && selectedProductForPanel.process_release_parameters.length > 0 && (
              <div>
                <h3 className="text-lg font-semibold text-gray-900 mb-3">Parámetros de Liberación del Proceso</h3>
                <div className="space-y-4">
                  {selectedProductForPanel.process_release_parameters.map((subprocess, index) => (
                    <div key={index} className="border border-gray-200 rounded-lg p-4">
                      <h4 className="font-medium text-gray-900 mb-3">
                        {subprocess.sequence}. {subprocess.subprocess_name}
                      </h4>
                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                        {subprocess.parameters.map((param, paramIndex) => (
                          <div key={paramIndex} className="bg-gray-50 p-3 rounded">
                            <div className="text-sm font-medium text-gray-700">{param.name}</div>
                            <div className="text-sm text-gray-900">
                              {param.type === 'exact' && `${param.value} ${param.unit}`}
                              {param.type === 'range' && `${param.min}-${param.max} ${param.unit}`}
                              {param.type === 'min' && `≥ ${param.value} ${param.unit}`}
                              {param.type === 'max' && `≤ ${param.value} ${param.unit}`}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            <div className="flex justify-end space-x-3">
              <Button
                onClick={() => setShowProductPanel(false)}
                className="btn-secondary"
              >
                Cerrar
              </Button>
            </div>
          </div>
        )}
      </Modal>
    </div>
  );
};

export default Products;
